from openai_agents import Runner, Agent
from vex_sdk import VexGuardrail

def detect_handoff_loops(runner_traces):
    loop_patterns = []
    for trace in runner_traces:
        handoffs = [step for step in trace.steps if 'handoff' in step.get('type', '')]
        if len(handoffs) > 5 and len(set(h[0] for h in handoffs)) < 3:
            loop_patterns.append({
                'agent_loop': [h[0] for h in handoffs[-3:]],
                'duration': trace.duration,
                'cost': trace.total_cost
            })
    return loop_patterns

import re
from openai_agents import Runner

def detect_prompt_injection(inputs):
    injection_patterns = [
        r'ignore.*previous.*instructions',
        r'you are.*new.*role',
        r'forget.*system',
        r'override.*guardrails'
    ]
    violations = []
    for inp in inputs:
        for pattern in injection_patterns:
            if re.search(pattern, inp['content'], re.IGNORECASE):
                violations.append({
                    'input_id': inp['id'],
                    'pattern': pattern,
                    'timestamp': inp['timestamp']
                })
    return violations

from openai_agents import ToolCallResult
import json

def validate_tool_output(tool_result: ToolCallResult, schema):
    try:
        parsed = json.loads(tool_result.content)
        # Validate against expected schema structure
        required_fields = schema.get('required', [])
        missing = [f for f in required_fields if f not in parsed]
        if missing:
            return {'valid': False, 'errors': f'Missing fields: {missing}'}
        return {'valid': True}
    except json.JSONDecodeError:
        return {'valid': False, 'errors': 'Invalid JSON format'}

