from openai_agents import Runner, Agent
from vex_sdk import VexGuardrail

class SafeRunner(Runner):
    def __init__(self, *args, max_handoffs=5, **kwargs):
        super().__init__(*args, **kwargs)
        self.max_handoffs = max_handoffs
        self.handoff_count = 0

    def execute(self, *args, **kwargs):
        if self.handoff_count >= self.max_handoffs:
            return {'error': 'Handoff limit exceeded', 'status': 'circuit_breaker'}
        result = super().execute(*args, **kwargs)
        self.handoff_count += result.get('handoffs', 0)
        return result

from openai_agents import Tool, ToolCallResult
from vex_sdk import VexSchemaValidator

validator = VexSchemaValidator({
    'type': 'object',
    'properties': {'data': {'type': 'array'}}
})

def safe_tool_call(tool: Tool):
    def validated_call(*args, **kwargs):
        raw_result = tool(*args, **kwargs)
        validation = validator.validate(raw_result)
        if not validation.valid:
            return ToolCallResult(
                content='{"error": "Invalid tool output format"}',
                tool_id=tool.id
            )
        return ToolCallResult(content=str(raw_result), tool_id=tool.id)
    return validated_call
